import React, { useState, useEffect } from "react";
import axios from 'axios';
import { useNavigate } from 'react-router-dom';
import Nav from './Nev';

// ============================================================
// 🔴 STEP 1: Razorpay pe free account banao:
//    https://dashboard.razorpay.com
// 🔴 STEP 2: Settings > API Keys > "Generate Test Key"
// 🔴 STEP 3: Key ID yahan paste karo (rzp_test_xxxxxxx)
// ============================================================
const RAZORPAY_KEY_ID = "rzp_test_Sq7J7mRZo6zCD1";

const Checkout = () => {
    const [paymentLoading, setPaymentLoading] = useState(false);
    const [paymentDone, setPaymentDone] = useState(false);
    const [paymentId, setPaymentId] = useState('');

    const localdata = parseInt(localStorage.getItem("item") || 0);
    const deleteid = localStorage.getItem("id") || 0;
    const userName = localStorage.getItem("uname") || "Customer";
    const userEmail = localStorage.getItem("email") || "customer@example.com";
    const navigate = useNavigate();

    useEffect(() => {
        if (!localStorage.getItem("islogin")) { navigate('/login'); return; }
        // Razorpay script preload
        if (!window.Razorpay) {
            const script = document.createElement('script');
            script.src = 'https://checkout.razorpay.com/v1/checkout.js';
            document.body.appendChild(script);
        }
    }, []);

    function clearCart() {
        fetch('http://localhost/Petshop/deletecart.php?uid=' + deleteid)
            .catch(err => console.log(err));
    }

    function saveOrder(orderId) {
        axios({
            method: "POST",
            url: "http://localhost/Petshop/order.php",
            data: {
                pid: localStorage.getItem("pid") || 1,
                order_id: orderId,
                uid: deleteid,
                totalitem: localStorage.getItem("totalitem") || 1,
                amount: localdata
            },
            headers: { "Content-Type": "multipart/form-data" },
        }).catch(err => console.log(err));
    }

    const handleRazorpayPayment = () => {
        if (!window.Razorpay) {
            alert("Page reload karein aur dobara try karein.");
            return;
        }

        setPaymentLoading(true);

        const options = {
            key: RAZORPAY_KEY_ID,
            amount: localdata * 100, // Paise mein
            currency: "INR",
            name: "Petology Pet Shop",
            description: "Pet Purchase Payment",
            image: "https://i.imgur.com/n5tjHFD.png",
            handler: function (response) {
                // ✅ Payment SUCCESS - yahan aata hai
                const pid = response.razorpay_payment_id;
                setPaymentId(pid);
                saveOrder(pid);
                clearCart();
                setPaymentDone(true);
                setPaymentLoading(false);
            },
            prefill: {
                name: userName,
                email: userEmail,
                contact: "" // user ka phone add kar sakte ho
            },
            notes: { address: "Petology Pet Shop" },
            theme: { color: "#38a169" },
            modal: {
                ondismiss: function () {
                    setPaymentLoading(false);
                }
            }
        };

        try {
            const rzp = new window.Razorpay(options);
            rzp.on('payment.failed', function (response) {
                setPaymentLoading(false);
                alert("❌ Payment fail: " + response.error.description);
            });
            rzp.open();
        } catch (err) {
            setPaymentLoading(false);
            alert("Razorpay Key sahi nahi hai. RAZORPAY_KEY_ID update karein.");
        }
    };

    // ✅ Payment Success Screen
    if (paymentDone) {
        return (
            <div style={s.page}>
                <Nav />
                <div style={s.container}>
