                <p style={s.subtitle}>100% Secure Payment — Razorpay powered</p>

                {/* Amount Box */}
                <div style={s.amountCard}>
                    <div>
                        <div style={s.amtLabel}>Total Payable</div>
                        <div style={s.amtValue}>₹{localdata.toLocaleString()}</div>
                        <div style={{ fontSize: '12px', color: '#a0aec0', marginTop: '2px' }}>
                            Free delivery included
                        </div>
                    </div>
                    <div style={{ fontSize: '52px' }}>🛍️</div>
                </div>

                {/* Payment Methods Info */}
                <div style={s.card}>
                    <div style={s.cardHeading}>Sabhi Payment Methods Available Hain</div>
                    <div style={s.methodGrid}>
                        {[
                            { icon: '📲', name: 'UPI', sub: 'PhonePe • GPay • Paytm • BHIM' },
                            { icon: '💳', name: 'Debit/Credit Card', sub: 'Visa • Mastercard • RuPay' },
                            { icon: '🏦', name: 'Net Banking', sub: 'SBI • HDFC • ICICI • Axis' },
                            { icon: '💰', name: 'Wallets', sub: 'Paytm • Amazon Pay • Freecharge' },
                        ].map((m, i) => (
                            <div key={i} style={s.methodBox}>
                                <span style={{ fontSize: '26px' }}>{m.icon}</span>
                                <span style={s.mName}>{m.name}</span>
                                <span style={s.mSub}>{m.sub}</span>
                            </div>
                        ))}
                    </div>

                    {/* Security */}
                    <div style={s.secRow}>
                        {['🔒 256-bit SSL', '✅ RBI Approved', '🛡️ PCI DSS Compliant'].map((b, i) => (
                            <span key={i} style={s.secBadge}>{b}</span>
                        ))}
                    </div>

                    {/* PAY BUTTON */}
                    <button
                        style={{ ...s.payBtn, opacity: paymentLoading ? 0.7 : 1 }}
                        onClick={handleRazorpayPayment}
                        disabled={paymentLoading}
                    >
                        {paymentLoading
                            ? '⏳ Payment window khul rahi hai...'
                            : `🔐 ₹${localdata.toLocaleString()} Abhi Pay Karein`}
                    </button>
                    <p style={s.poweredBy}>Powered by <strong>Razorpay</strong> — India's #1 Payment Gateway</p>
                </div>

                {/* Setup Guide */}
                <div style={s.infoBox}>
                    <div style={{ fontWeight: '700', color: '#92400e', marginBottom: '10px' }}>
                        ⚙️ Razorpay Setup (5 minutes mein):
                    </div>
                    <ol style={{ paddingLeft: '18px', color: '#78350f', fontSize: '13px', lineHeight: '2' }}>
                        <li>
                            <a href="https://dashboard.razorpay.com" target="_blank" rel="noreferrer"
                                style={{ color: '#d97706', fontWeight: '600' }}>
                                dashboard.razorpay.com
                            </a> pe jaao → Free account banao
                        </li>
                        <li>Settings → API Keys → "Generate Test Key" click karo</li>
                        <li>Key ID (rzp_test_xxx) copy karo</li>
                        <li>
                            <code style={{ background: '#fef3c7', padding: '1px 6px', borderRadius: '4px' }}>
                                RAZORPAY_KEY_ID
                            </code> mein paste karo (is file ke top pe)
                        </li>
                        <li>Payment test karo → Sab theek hone pe Live key use karo</li>
                    </ol>
                </div>

                <button style={s.backLink} onClick={() => navigate('/cart')}>
                    ← Cart pe wapas jaao
                </button>
            </div>
        </div>
    );
};

